output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(COUNT(?season) AS ?season_count) WHERE {
  wd:Q25205882 wdt:P527 ?season .
}
GROUP BY ?season_count

